B.Dv=new A.ba(null,"Seis (6) imagens foram apresentadas em algum momento do teste. Vamos encontr\xe1-los? Clique nas figuras que voc\xea lembrou. N\xe3o \xe9 obrigado(a) a encontrar todas as imagens. Fa\xe7a o seu melhor!\n",!1,null,null,null)
