B.DE=new A.ba(null,"assets/olho2.png",!0,null,null,null)
B.DF=new A.ba(null,"Na pr\xf3xima tela ser\xe1 reproduzida uma lista de 10 pares de palavras relacionadas logicamente entre si (p. ex., alto-baixo). Depois, voc\xea ser\xe1 solicitado para preencher a palavra faltante. Fique atento, voc\xea ter\xe1 que memorizar todos os pares.\n\nQuando estiver pronto \xe9 s\xf3 clicar em pr\xf3ximo...",!1,null,null,null)
B.DG=new A.ba(null,"Nas pr\xf3ximas 4 telas, ser\xe3o exibidas diversas express\xf5es representando diferentes sentimentos. Em cada tela, selecione pelo menos 3 e no m\xe1ximo 4 express\xf5es que melhor correspondem ao que voc\xea tem sentido nos \xfaltimos meses.\n\nQuando estiver pronto \xe9 s\xf3 clicar em pr\xf3ximo...",!1,null,null,null)
